using System;using System.Collections.Generic;public class Program{static int Solve(int[,]m,int k){int R=m.GetLength(0),C=m.GetLength(1),best=int.MinValue;for(int top=0;top<R;top++){int[]s=new int[C];for(int bot=top;bot<R;bot++){for(int c=0;c<C;c++)s[c]+=m[bot,c];var pre=new List<int>{0};int cur=0;foreach(int x in s){cur+=x;int target=cur-k;int i=pre.BinarySearch(target);if(i<0)i=~i;if(i<pre.Count)best=Math.Max(best,cur-pre[i]);int j=pre.BinarySearch(cur);if(j<0)j=~j;pre.Insert(j,cur);}}}return best;}public static void Main(){string[]d=Console.In.ReadToEnd().Split((char[])null,StringSplitOptions.RemoveEmptyEntries);if(d.Length==0)return;int idx=0,t=int.Parse(d[idx++]);var outv=new List<string>();for(int tc=0;tc<t;tc++){int r=int.Parse(d[idx++]),c=int.Parse(d[idx++]);var m=new int[r,c];for(int i=0;i<r;i++)for(int j=0;j<c;j++)m[i,j]=int.Parse(d[idx++]);int k=int.Parse(d[idx++]);outv.Add(Solve(m,k).ToString());}Console.Write(string.Join("\n\n",outv));}}
